CREATE VIEW results.v_pao2_fio2_pairs AS SELECT p.person_id, p.measurement_datetime AS pao2_time, p.value_as_number AS pao2, f.measurement_datetime AS fio2_time, CASE WHEN f.value_as_number>1 THEN f.value_as_number/100 ELSE f.value_as_number END AS fio2, ABS(EXTRACT(EPOCH FROM (f.measurement_datetime-p.measurement_datetime))/60) AS delta_min FROM cdm.measurement p JOIN cdm.measurement f ON p.person_id=f.person_id WHERE p.measurement_concept_id IN (SELECT descendant_concept_id FROM vocab.concept_ancestor WHERE ancestor_concept_id=3002647) AND f.measurement_concept_id IN (SELECT descendant_concept_id FROM vocab.concept_ancestor WHERE ancestor_concept_id=3013468) AND ABS(EXTRACT(EPOCH FROM (f.measurement_datetime-p.measurement_datetime))/60) <= 240 AND f.value_as_number IS NOT NULL;